// Give VS Code IntelliSense for uibuilder
// (not part of the code, just for type checking and auto-completion)
/// <reference path="../types/uibuilder.d.ts" />

// Listen for incoming messages from Node-RED and action
// This sets up a listener function. So you can set it up before
// other things if you want.
uibuilder.onChange('msg', (msg) => {
    // For example #3, we listen for a msg with `msg.deeper` and update the variable `setByJavaScript` with the value of `msg.deeper`.
    if (msg.deeper) {
        console.log('Received msg.deeper from Node-RED. Updating setByJavaScript.deep.deeper:', msg)
        // We can update this either way:
        // uibuilder.set('setByJavaScript', { deep: { deeper: msg.deeper } })
        uibuilder.set('setByJavaScript.deep.deeper', msg.deeper)
    }
})

// Create a uibuilder managed variable. We use this in the
// HTML for example #3. We don't have to do this of course
// It is fine for the variable to be undefined until we set it,
// but this way we can give it an initial value and structure.
//
// If we don't use a delay as in the code below, this default
// will likely never be seen in the page. Try this out by 
// stopping the update from Node-RED.
uibuilder.set('setByJavaScript', {
    deep: {
        deeper: 'This is the initial value of the variable setByJavaScript. It will be updated by a remote command from Node-RED.',
    },
})

// Page startup needs a bit of time to set up the custom web components.
// So we are delaying by a few ms. Alternatively,
// you could create a listener for the `uib-var:ready` event and run the set
// command in that. But, in practice, a short delay is usually sufficient.
setTimeout(() => {
    uibuilder.set('setByJavaScript2', {
        text: 'This variable is set by JavaScript after a delay of 10ms.',
        text2: 'Because of how JS works, it needs time to start before running this.',
        text3: 'It is not updated by a remote command from Node-RED.',
        text4: 'But, of course, it could come from Node-RED if we wanted it to.',
        obj: {
            nested: true,
            number: Math.random() * 100,
            int: 42,
            today: new Date(),
        },
    })    
}, 10);
